  "dossier": {
    "overview": "Shown under the hero on the public page.",
    "sections": [
      {
        "id": "intro",
        "title": "Section title",
        "summary": "Optional lede.",
        "blocks": [{ "type": "text", "body": "…" }]
      }
    ]
  }
}

registerDossierBlock({
  type: 'text',
  label: 'Text note',
  normalize(block) {
    const body = String(block.body || '').trim();
    return body ? { type: 'text', body } : null;
  },
});

